const title = ($json.title || "").toLowerCase();
let category = "General Announcement";

const mappings = [
  {
    category: "Financial Results",
    patterns: ["quarterly results", "q1 results", "q2 results", "q3 results", "q4 results", "financial results", "annual results", "unaudited results", "audited results"]
  },
  {
    category: "Board Meeting",
    patterns: ["board meeting", "board of directors", "board meeting notice"]
  },
  {
    category: "Shareholder Meeting",
    patterns: ["agm", "annual general meeting", "egm", "extraordinary general meeting", "notice of agm", "notice of egm"]
  },
  {
    category: "Dividend",
    patterns: ["dividend", "interim dividend", "final dividend", "special dividend"]
  },
  {
    category: "Buyback",
    patterns: ["buyback", "buy back", "share repurchase"]
  },
  {
    category: "M&A",
    patterns: ["merger", "acquisition", "amalgamation", "demerger", "scheme of arrangement", "takeover", "open offer"]
  },
  {
    category: "Capital Raise",
    patterns: ["qip", "qualified institutional placement", "fpo", "follow-on", "rights issue", "ncd", "non-convertible debentures"]
  },
  {
    category: "Order Win",
    patterns: ["order win", "order received", "contract awarded", "letter of intent", "loi received", "secured order", "new order"]
  },
  {
    category: "Regulatory",
    patterns: ["insider trading", "insider dealing", "sast regulations", "substantial acquisition"]
  }
];

for (const map of mappings) {
  let matched = false;
  for (const pattern of map.patterns) {
    if (title.includes(pattern)) {
      category = map.category;
      matched = true;
      break;
    }
  }
  if (matched) break;
}

$json.event_category = category;
return $json;

