parameters.jsCode:
let rawResponse = "";
if ($json.response) {
  rawResponse = $json.response.trim();
} else if ($json.body && $json.body.response) {
  rawResponse = $json.body.response.trim();
}

let company_name = "Unknown";
let event_type = "Unknown";
let sentiment = "Unknown";
let impact_score = 5;

function cleanSentiment(val) {
  if (!val) return "Unknown";
  const s = val.toString().trim().toLowerCase();
  if (s.includes("pos")) return "Positive";
  if (s.includes("neg")) return "Negative";
  if (s.includes("neu")) return "Neutral";
  return "Unknown";
}

function cleanImpactScore(val) {
  if (val === undefined || val === null) return 5;
  const match = val.toString().match(/\d+/);
  if (match) {
    const score = parseInt(match[0], 10);
    return isNaN(score) ? 5 : score;
  }
  return 5;
}

try {
  let jsonStr = rawResponse;
  const codeBlockMatch = rawResponse.match(/```(?:json)?\s*([\s\S]*?)\s*```/i);
  if (codeBlockMatch) {
    jsonStr = codeBlockMatch[1];
  }

  const firstBrace = jsonStr.indexOf('{');
  const lastBrace = jsonStr.lastIndexOf('}');
  if (firstBrace !== -1 && lastBrace !== -1) {
    jsonStr = jsonStr.substring(firstBrace, lastBrace + 1);
  }

  const parsed = JSON.parse(jsonStr);

  if (parsed.company_name) company_name = parsed.company_name.toString().trim();
  if (parsed.event_type) event_type = parsed.event_type.toString().trim();
  if (parsed.sentiment) sentiment = cleanSentiment(parsed.sentiment);
  if (parsed.impact_score !== undefined) impact_score = cleanImpactScore(parsed.impact_score);
} catch (e) {
  const companyMatch = rawResponse.match(/"company_name"\s*:\s*"([^"]+)"/i) || rawResponse.match(/company_name\s*:\s*([^\n,]+)/i);
  if (companyMatch) company_name = companyMatch[1].replace(/["']/g, "").trim();

  const eventMatch = rawResponse.match(/"event_type"\s*:\s*"([^"]+)"/i) || rawResponse.match(/event_type\s*:\s*([^\n,]+)/i);
  if (eventMatch) event_type = eventMatch[1].replace(/["']/g, "").trim();

  const sentimentMatch = rawResponse.match(/"sentiment"\s*:\s*"([^"]+)"/i) || rawResponse.match(/sentiment\s*:\s*([^\n,]+)/i);
  if (sentimentMatch) sentiment = cleanSentiment(sentimentMatch[1]);

  const impactMatch = rawResponse.match(/"impact_score"\s*:\s*(\d+)/i) || rawResponse.match(/impact_score\s*:\s*(\d+)/i);
  if (impactMatch) impact_score = cleanImpactScore(impactMatch[1]);
}

// Fetch data from previous node
const prevData = $('Event Category').item.json;

return {
  article_id: prevData.article_id || "",
  title: prevData.title || "",
  content: prevData.content || "",
  link: prevData.link || "",
  source_feed: prevData.source_feed || "BSE",
  published_at: prevData.published_at || new Date().toISOString(),
  event_category: prevData.event_category || "General Announcement",
  company_name: company_name,
  event_type: event_type,
  sentiment: sentiment,
  impact_score: impact_score,
  raw_response: rawResponse
};
